import random, signal, solution
rng = random.Random(12345)
n = 200000
ops = []
for _ in range(200000):
    if rng.random() < 0.5:
        ops.append(('set', rng.randrange(n), rng.randrange(-1000, 1000)))
    else:
        l = rng.randrange(n); r = rng.randrange(l, n)
        ops.append(('sum', l, r))
# expected answers via Fenwick
tree = [0] * (n + 1); cur = [0] * n
def upd(i, d):
    i += 1
    while i <= n:
        tree[i] += d; i += i & (-i)
def pre(i):
    s = 0
    while i > 0:
        s += tree[i]; i -= i & (-i)
    return s
expected = []
for op in ops:
    if op[0] == 'set':
        _, i, v = op; upd(i, v - cur[i]); cur[i] = v
    else:
        _, l, r = op; expected.append(pre(r + 1) - pre(l))
class _TO(Exception): pass
def _h(s, f): raise _TO()
signal.signal(signal.SIGALRM, _h)
signal.setitimer(signal.ITIMER_REAL, 5.0)
try:
    got = solution.process(n, [tuple(o) for o in ops])
finally:
    signal.setitimer(signal.ITIMER_REAL, 0)
assert list(got) == expected, 'wrong answers'
print('OK')
PYEOF
)"

