import math, random, json, solution
INST=[(0, 60), (1, 120), (2, 180)]
REF={0:6195.97445814033,1:8743.12899328959,2:10615.721199788375}
def gp(seed,n):
    r=random.Random(1000+seed);return [(r.random()*1000,r.random()*1000) for _ in range(n)]
def d(a,b):return math.hypot(a[0]-b[0],a[1]-b[1])
def tl(p,t):return sum(d(p[t[i]],p[t[(i+1)%len(t)]]) for i in range(len(t)))
ratios=[]
for seed,n in INST:
    p=gp(seed,n)
    tour=list(solution.solve([tuple(x) for x in p]))
    assert sorted(tour)==list(range(n)),'not a valid permutation for seed '+str(seed)
    L=tl(p,tour)
    ratios.append(min(1.0, REF[seed]/L) if L>0 else 0.0)
score=sum(ratios)/len(ratios)
json.dump({'score':score},open('score.json','w'))
print('score=%.4f ratios=%s'%(score,[round(r,3) for r in ratios]))
PYEOF
